import mysql.connector

def import_data_with_load_data_infile(db_config, table_name, file_path, fields_terminated_by=',', optionally_enclosed_by='"', lines_terminated_by='\n', ignore_lines=1):
    """
    Imports data into a MySQL table using the LOAD DATA INFILE statement.

    Args:
        db_config (dict): Dictionary containing database connection parameters
                          (host, user, password, database).
        table_name (str): The name of the target table in MySQL.
        file_path (str): The absolute path to the data file on the client machine.
        fields_terminated_by (str): The character sequence that terminates field values.
        optionally_enclosed_by (str): The character that encloses field values (e.g., for strings).
        lines_terminated_by (str): The character sequence that terminates lines.
        ignore_lines (int): The number of lines to ignore at the beginning of the file (e.g., header).
    """
    conn = None
    try:
        # Establish connection with local_infile enabled
        conn = mysql.connector.connect(
            host=db_config['host'],
            user=db_config['user'],
            password=db_config['password'],
            database=db_config['database'],
            allow_local_infile=True # Enable LOCAL INFILE for the Python connector
        )
        cursor = conn.cursor()

        # Construct the LOAD DATA INFILE statement
        # Using format for file_path as requested.
        # Be aware of SQL injection risks if table_name or other parameters
        # were user-supplied directly without validation. For file_path,
        # it's usually less of a direct injection risk for the SQL query structure,
        # but path traversal or privilege escalation can still be concerns if
        # the path is not properly validated.
        load_data_sql = (
            f"LOAD DATA LOCAL INFILE '{file_path}' "
            f"INTO TABLE {table_name} "
            f"FIELDS TERMINATED BY '{fields_terminated_by}' "
            f"OPTIONALLY ENCLOSED BY '{optionally_enclosed_by}' "
            f"LINES TERMINATED BY '{lines_terminated_by}' "
            f"IGNORE {ignore_lines} LINES;"
        )

        print(f"Executing: {load_data_sql}")
        cursor.execute(load_data_sql)
        conn.commit()
        print(f"Successfully imported data from '{file_path}' into table '{table_name}'.")
        print(f"Rows affected: {cursor.rowcount}")

    except mysql.connector.Error as err:
        print(f"Error: {err}")
        if conn and conn.is_connected():
            conn.rollback()
    finally:
        if conn and conn.is_connected():
            cursor.close()
            conn.close()
            print("MySQL connection closed.")

